// src/App.jsx
import React, { useState, useEffect } from 'react';
import { IntlProvider, useIntl } from 'react-intl';
import { MapContainer, TileLayer, Polyline, Marker, useMap } from 'react-leaflet';
import 'leaflet/dist/leaflet.css';
import L from 'leaflet';
import gpsData from './frontend_data_gps.json';
import ptBR from './i18n/locales/pt-BR.json';
import './App.scss';

// Fix para ├Łcone do Leaflet
delete L.Icon.Default.prototype._getIconUrl;
L.Icon.Default.mergeOptions({
  iconRetinaUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/images/marker-icon-2x.png',
  iconUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/images/marker-icon.png',
  shadowUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/images/marker-shadow.png',
});

// Componente do sprite do carro com anima├¦├Żo baseada na dire├¦├Żo
const CarSprite = ({ direction = 0, color = '#FFEB3B' }) => {
  // 72 frames para 360 graus = 5 graus por frame
  const frameIndex = Math.min(Math.floor(direction / 5), 71);
  const positionX = frameIndex * 60; // 60px por frame
  
  return (
    <div 
      style={{
        width: '60px',
        height: '60px',
        backgroundImage: `url(${process.env.PUBLIC_URL}/sprites/car-sprite.png)`,
        backgroundPosition: `-${positionX}px 0`,
        backgroundSize: '4320px 60px', // 72 frames ├Ś 60px
        backgroundRepeat: 'no-repeat',
        transform: 'translate(-50%, -50%)',
        position: 'relative'
      }}
    >
      {/* Indicador de cor do ve├Łculo */}
      <div style={{
        position: 'absolute',
        bottom: '-5px',
        left: '50%',
        transform: 'translateX(-50%)',
        width: '10px',
        height: '10px',
        borderRadius: '50%',
        backgroundColor: color,
        border: '2px solid white'
      }} />
    </div>
  );
};

// Componente para atualizar o centro do mapa quando a posi├¦├Żo mudar
const MapCenterUpdater = ({ position }) => {
  const map = useMap();
  useEffect(() => {
    if (position) {
      map.setView([position.latitude, position.longitude], 14);
    }
  }, [position, map]);
  return null;
};

// Componente principal do App
const AppContent = () => {
  const intl = useIntl();
  const [selectedCourse, setSelectedCourse] = useState(0);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isPlaying, setIsPlaying] = useState(false);
  const [animationSpeed, setAnimationSpeed] = useState(1000); // ms entre frames

  const vehicle = gpsData.vehicle;
  const courses = gpsData.courses || [];
  const currentCourse = courses[selectedCourse];
  const gpsPoints = currentCourse?.gps || [];
  const currentPoint = gpsPoints[currentIndex];

  // Anima├¦├Żo: percorre os pontos GPS quando est├Ī "play"
  useEffect(() => {
    if (!isPlaying || !gpsPoints.length) return;
    
    const interval = setInterval(() => {
      setCurrentIndex(prev => {
        if (prev >= gpsPoints.length - 1) {
          setIsPlaying(false); // Para no final
          return prev;
        }
        return prev + 1;
      });
    }, animationSpeed);

    return () => clearInterval(interval);
  }, [isPlaying, animationSpeed, gpsPoints.length]);

  // Preparar pontos da rota para o Leaflet
  const routePositions = gpsPoints.map(p => [p.latitude, p.longitude]);

  // Calcular estat├Łsticas
  const stats = {
    distance: (currentCourse?.distance / 1000)?.toFixed(2),
    duration: Math.floor((currentCourse?.duration || 0) / 60),
    avgSpeed: currentCourse?.speed_avg?.toFixed(1),
    maxSpeed: currentCourse?.speed_max?.toFixed(1)
  };

  return (
    <div className="app">
      {/* Header */}
      <header className="app__header">
        <h1>­¤ÜŚ {intl.formatMessage({ id: 'app.title', defaultMessage: 'Rastreamento 3D' })}</h1>
        <p>{vehicle.plate} ŌĆó {vehicle.vin}</p>
      </header>

      <main className="app__main">
        <div className="app__grid">
          {/* Sidebar: Informa├¦├Ąes + Controles */}
          <aside className="app__sidebar">
            {/* Informa├¦├Ąes do ve├Łculo */}
            <div className="vehicle-info">
              <h3>­¤ōŖ {intl.formatMessage({ id: 'vehicle.title', defaultMessage: 'Ve├Łculo' })}</h3>
              <div className="info-grid">
                <div><strong>Placa:</strong> {vehicle.plate}</div>
                <div><strong>Cor:</strong> <span style={{ color: vehicle.color }}>ŌŚÅ</span></div>
                {currentPoint && (
                  <>
                    <div><strong>Velocidade:</strong> {currentPoint.speed?.toFixed(1)} km/h</div>
                    <div><strong>Dire├¦├Żo:</strong> {currentPoint.direction?.toFixed(1)}┬░</div>
                  </>
                )}
              </div>
            </div>

            {/* Estat├Łsticas da rota */}
            <div className="route-stats">
              <h3>­¤ōł {intl.formatMessage({ id: 'stats.title', defaultMessage: 'Estat├Łsticas' })}</h3>
              <div className="stats-grid">
                <div><strong>Dist├óncia:</strong> {stats.distance} km</div>
                <div><strong>Dura├¦├Żo:</strong> {stats.duration} min</div>
                <div><strong>M├®dia:</strong> {stats.avgSpeed} km/h</div>
                <div><strong>M├Īxima:</strong> {stats.maxSpeed} km/h</div>
              </div>
            </div>

            {/* Seletor de rotas (B├öNUS) */}
            <div className="route-selector">
              <h3>­¤Ś║’ĖÅ {intl.formatMessage({ id: 'routes.title', defaultMessage: 'Rotas' })}</h3>
              <select 
                value={selectedCourse} 
                onChange={(e) => {
                  setSelectedCourse(Number(e.target.value));
                  setCurrentIndex(0);
                  setIsPlaying(false);
                }}
                className="route-select"
              >
                {courses.map((_, idx) => (
                  <option key={idx} value={idx}>
                    {intl.formatMessage({ id: 'routes.course', defaultMessage: 'Rota' })} {idx + 1}
                  </option>
                ))}
              </select>
            </div>

            {/* Controles de anima├¦├Żo (B├öNUS: velocidade) */}
            <div className="animation-controls">
              <button onClick={() => setIsPlaying(!isPlaying)} className="btn-primary">
                {isPlaying ? 'ŌÅĖ’ĖÅ Pausar' : 'Ō¢Č’ĖÅ Reproduzir'}
              </button>
              <button onClick={() => { setCurrentIndex(0); setIsPlaying(false); }} className="btn-secondary">
                ­¤öä Reiniciar
              </button>
              <div className="speed-control">
                <label>Velocidade:</label>
                <select value={animationSpeed} onChange={(e) => setAnimationSpeed(Number(e.target.value))}>
                  <option value={2000}>­¤Éó Lento</option>
                  <option value={1000}>­¤ÜČ Normal</option>
                  <option value={500}>­¤Åā R├Īpido</option>
                  <option value={200}>ŌÜĪ Turbo</option>
                </select>
              </div>
            </div>
          </aside>

          {/* Mapa */}
          <section className="app__map-wrapper">
            <MapContainer 
              center={[currentPoint?.latitude || -23.963214, currentPoint?.longitude || -46.28054]} 
              zoom={14} 
              className="map-container"
            >
              <MapCenterUpdater position={currentPoint} />
              <TileLayer
                url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
                attribution='&copy; OpenStreetMap'
              />
              
              {/* Linha da rota */}
              {routePositions.length > 1 && (
                <Polyline 
                  positions={routePositions} 
                  color="#FFC107" 
                  weight={3} 
                  opacity={0.7}
                  dashArray="5, 5"
                />
              )}
              
              {/* Marker do carro com sprite animado */}
              {currentPoint && (
                <Marker position={[currentPoint.latitude, currentPoint.longitude]}>
                  <CarSprite 
                    direction={currentPoint.direction || 0} 
                    color={vehicle.color} 
                  />
                </Marker>
              )}
            </MapContainer>
          </section>
        </div>
      </main>

      <footer className="app__footer">
        <p>Projeto t├®cnico ŌĆó React + Leaflet + SCSS + i18n</p>
      </footer>
    </div>
  );
};

// Wrapper com IntlProvider
const App = () => {
  // Prote├¦├Żo contra dados n├Żo carregados
  if (!gpsData?.vehicle) {
    return <div style={{ padding: '2rem' }}>ŌÜĀ’ĖÅ Carregando dados...</div>;
  }

  return (
    <IntlProvider locale="pt-BR" messages={ptBR} defaultLocale="pt-BR">
      <AppContent />
    </IntlProvider>
  );
};

export default App;
